function buildPhaseFromInput(input: { name: string; tasks?: Array<{ content: string; status?: string; notes?: string; details?: string }> }, phaseId: string, nextTaskId: number): { phase: TodoPhase; nextTaskId: number } {
  const tasks: TodoItem[] = [];
  let tid = nextTaskId;
  for (const t of input.tasks ?? []) {
    // Cast status to TodoStatus if valid, otherwise default to pending
    let status: TodoStatus = "pending";
    if (t.status && ["pending", "in_progress", "completed", "abandoned"].includes(t.status)) {
      status = t.status as TodoStatus;
    }
    tasks.push({
      id: `task-${tid++}`,
      content: t.content,
      status,
      notes: t.notes,
      details: t.details,
    });
  }
  return { phase: { id: phaseId, name: input.name, tasks }, nextTaskId: tid };
}

